/**
 * @summary Returns the platform's OAuth URL to start connection
 */
export const getGetAdAccountConnectUrlUrl = (
  params: GetAdAccountConnectUrlParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/ad-accounts/connect-url?${stringifiedParams}`
    : `/api/ad-accounts/connect-url`;
};

